@@ -930,8 +963,27 @@ mod tests {
         let finding = &report.findings[0];
         assert_eq!(finding.agent.as_deref(), Some("gemini"));
         assert_eq!(finding.workspace.as_deref(), Some("/home/user/myproject"));
-        assert!(finding.source_path.is_some());
